import{m as t,aU as a,z as l,M as r}from"./chunks/framework.LN92DB6A.js";const i=JSON.parse('{"title":"2026广州积分入户最新攻略：条件、分值、申请全流程","description":"想把户口迁到广州？积分入户是最主流通道。本文详解申请条件、积分指标体系和完整申请流程。","frontmatter":{"title":"2026广州积分入户最新攻略：条件、分值、申请全流程","tags":["广州","积分入户","落户","户口","来穗人员"],"categories":["办事攻略"],"date":"2026-05-30T00:00:00.000Z","description":"想把户口迁到广州？积分入户是最主流通道。本文详解申请条件、积分指标体系和完整申请流程。","head":[["link",{"rel":"canonical","href":"https://guangzhou.suporka.site/posts/2026/points-settlement"}]]},"headers":[],"relativePath":"posts/2026/points-settlement.md","filePath":"posts/2026/points-settlement.md","lastUpdated":1779868425000}');const e=t({name:"posts/2026/points-settlement.md"},[["render",function(t,i,e,o,s,n){return a(),l("div",null,[...i[0]||(i[0]=[r('<p>在广州打拼多年，想把户口落下来？积分入户是最主流的通道之一——不看学历高低、不需要投资纳税，靠的是你在广州的综合贡献。</p><p>简单说：<strong>满足基本条件 → 核定积分 → 排名入围 → 办理入户。</strong></p><h2 id="申请条件" tabindex="-1">申请条件 <a class="header-anchor" href="#申请条件" aria-label="Permalink to &quot;申请条件&quot;">​</a></h2><p>申请积分入户需要同时满足以下条件：</p><ul><li>年龄<strong>45周岁以下</strong></li><li>持有有效<strong>广东省居住证</strong>（广州）</li><li>在广州<strong>合法稳定就业</strong>或<strong>合法稳定居住</strong></li><li>在广州缴纳<strong>社会保险</strong>满<strong>4年</strong>（含）以上</li><li>近5年内<strong>无犯罪记录</strong></li><li>按照《广州市来穗人员积分制服务管理指标体系及分值表》计算总积分</li></ul><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>社保年限是硬性门槛，中间断缴会影响连续性计算。如果是灵活就业参保，也要确保连续缴纳。</p></div><h2 id="积分怎么算" tabindex="-1">积分怎么算 <a class="header-anchor" href="#积分怎么算" aria-label="Permalink to &quot;积分怎么算&quot;">​</a></h2><p>广州积分入户的积分由<strong>基础指标</strong>和<strong>加分指标</strong>组成。</p><h3 id="基础指标" tabindex="-1">基础指标 <a class="header-anchor" href="#基础指标" aria-label="Permalink to &quot;基础指标&quot;">​</a></h3><div class="table-container"><table><thead><tr><th>指标</th><th>说明</th></tr></thead><tbody><tr><td>合法稳定住所</td><td>在广州有自有住房、租房并办理租赁备案等</td></tr><tr><td>合法稳定就业</td><td>在广州就业并缴纳社保</td></tr><tr><td>年龄</td><td>18-40岁满分，41-45岁逐岁递减</td></tr></tbody></table></div><h3 id="加分指标" tabindex="-1">加分指标 <a class="header-anchor" href="#加分指标" aria-label="Permalink to &quot;加分指标&quot;">​</a></h3><div class="table-container"><table><thead><tr><th>指标</th><th>说明</th></tr></thead><tbody><tr><td>学历</td><td>本科及以上、大专、高中/中专等不同分值</td></tr><tr><td>技能证书</td><td>国家职业资格证书、专业技术资格</td></tr><tr><td>纳税</td><td>近3年在广州的个人所得税纳税额</td></tr><tr><td>社会服务</td><td>无偿献血、志愿服务、慈善捐赠等</td></tr><tr><td>创新创业</td><td>专利、高新技术企业等</td></tr><tr><td>住房公积金</td><td>缴存年限</td></tr></tbody></table></div><h3 id="减分指标" tabindex="-1">减分指标 <a class="header-anchor" href="#减分指标" aria-label="Permalink to &quot;减分指标&quot;">​</a></h3><ul><li>信用不良记录</li><li>违法犯罪记录</li><li>失信被执行人</li></ul><p>具体分值以广州市来穗人员服务管理局公布的最新版本为准。建议登录<strong>广州市来穗人员积分制服务管理信息系统</strong>查看详细分值表。</p><h2 id="如何核定积分" tabindex="-1">如何核定积分 <a class="header-anchor" href="#如何核定积分" aria-label="Permalink to &quot;如何核定积分&quot;">​</a></h2><h3 id="线上操作" tabindex="-1">线上操作 <a class="header-anchor" href="#线上操作" aria-label="Permalink to &quot;线上操作&quot;">​</a></h3><ol><li>登录<strong>广州市来穗人员积分制服务管理信息系统</strong><ul><li>网址：lsj.gz.gov.cn（或通过穗好办APP进入）</li></ul></li><li>注册并实名认证</li><li>填写个人信息，逐项录入积分指标</li><li>上传证明材料（学历证书、技能证书、纳税证明等）</li><li>提交积分核定申请</li><li>等待审核（一般需要15-30个工作日）</li></ol><h3 id="线下办理" tabindex="-1">线下办理 <a class="header-anchor" href="#线下办理" aria-label="Permalink to &quot;线下办理&quot;">​</a></h3><p>到居住地所在区的<strong>来穗人员服务管理中心</strong>提交材料，由工作人员协助办理。</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>积分核定需要时间，不要等到入户申请开始了才去核定积分。建议提前半年以上完成积分核定。</p></div><h2 id="申请流程" tabindex="-1">申请流程 <a class="header-anchor" href="#申请流程" aria-label="Permalink to &quot;申请流程&quot;">​</a></h2><p>积分入户每年开放一次申请，大致流程如下：</p><h3 id="_1-积分核定" tabindex="-1">1. 积分核定 <a class="header-anchor" href="#_1-积分核定" aria-label="Permalink to &quot;1. 积分核定&quot;">​</a></h3><p>在申请期前完成积分核定（建议提前半年）。</p><h3 id="_2-网上申请" tabindex="-1">2. 网上申请 <a class="header-anchor" href="#_2-网上申请" aria-label="Permalink to &quot;2. 网上申请&quot;">​</a></h3><p>在规定申请期内，通过积分制系统提交入户申请。</p><h3 id="_3-排名公示" tabindex="-1">3. 排名公示 <a class="header-anchor" href="#_3-排名公示" aria-label="Permalink to &quot;3. 排名公示&quot;">​</a></h3><p>按照总积分从高到低排名，公示入围名单。各区有不同的入户指标名额。</p><h3 id="_4-办理入户手续" tabindex="-1">4. 办理入户手续 <a class="header-anchor" href="#_4-办理入户手续" aria-label="Permalink to &quot;4. 办理入户手续&quot;">​</a></h3><p>入围后，按通知要求到公安部门办理户口迁移手续。所需材料：</p><ul><li>身份证</li><li>入户卡（积分入户核准卡）</li><li>户口簿</li><li>迁入地相关证明（房产证或单位集体户口同意书等）</li></ul><h2 id="历年入围分数参考" tabindex="-1">历年入围分数参考 <a class="header-anchor" href="#历年入围分数参考" aria-label="Permalink to &quot;历年入围分数参考&quot;">​</a></h2><p>每年的入围分数线取决于当年的申请人数和入户指标数量。积分越高越稳。</p><p>影响入围的关键因素：</p><ul><li>社保年限（越长越好）</li><li>居住证年限（越长越好）</li><li>年龄（18-40岁最优）</li><li>住房情况（自有住房加分较多）</li><li>学历和技能证书</li></ul><h2 id="配偶和子女随迁" tabindex="-1">配偶和子女随迁 <a class="header-anchor" href="#配偶和子女随迁" aria-label="Permalink to &quot;配偶和子女随迁&quot;">​</a></h2><p>积分入户成功后，配偶和未成年子女可以随迁：</p><ul><li><strong>配偶随迁</strong>：需要结婚证、配偶身份证和户口簿</li><li><strong>子女随迁</strong>：需要出生证明、子女户口簿</li></ul><p>随迁手续在入户时一并办理，也可以后续单独申请。</p><h2 id="避坑提醒" tabindex="-1">避坑提醒 <a class="header-anchor" href="#避坑提醒" aria-label="Permalink to &quot;避坑提醒&quot;">​</a></h2><ul><li><strong>积分核定要提前做</strong>：不能临阵磨枪，核定流程需要15-30个工作日，材料不齐还会被退回</li><li><strong>虚假材料后果严重</strong>：一经查实取消申请资格，3年内不得再次申请，还可能被列入失信名单</li><li><strong>社保不能断</strong>：4年社保是硬性门槛，且断缴会影响连续性计算</li><li><strong>居住证要保持有效</strong>：居住证过期未签注会影响申请</li><li><strong>每年只有一次机会</strong>：错过申请期只能等下一年</li><li><strong>各区名额不同</strong>：选择入户区域时考虑各区的竞争激烈程度</li><li><strong>房产不是必须的</strong>：没有房产可以入单位集体户或公共集体户</li></ul><p>积分入户是一个长期积累的过程，越早开始准备越好。在广州踏实工作、按时缴社保、保持居住证有效，积分自然会越来越高。</p><blockquote><p>相关阅读：<a href="/posts/2026/residence-permit">广州居住证办理攻略</a> | <a href="/posts/2026/social-security">广州社保查询与办事指南</a></p></blockquote>',44)])])}]]);export{i as __pageData,e as default};
